import { useState } from "react";
import { useNavigate } from "react-router-dom";

function Layout({ children }) {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));

  // ✅ GLOBAL STATE HERE
  const [filter, setFilter] = useState("recent");
  const [category, setCategory] = useState("all");

  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <div className="layout">

      {/* NAVBAR */}
      <div className="nav">
        <div className="nav-left">
          <div className="logo">C</div>
          <div>
            <h3>Campus Connect</h3>
            <p>Student Learning Hub</p>
          </div>
        </div>

        <div className="nav-right">
          <div className="profile">
            <div className="avatar">{user?.name?.[0]}</div>
            <div>
              <p>{user?.name}</p>
              <span>{user?.role}</span>
            </div>
          </div>

          <button onClick={handleLogout}>Logout</button>
        </div>
      </div>

      {/* BODY */}
      <div className="layout-body">

        {/* SIDEBAR */}
        <div className="sidebar">

          <h4>Filters</h4>

          <button onClick={() => setFilter("recent")}>
            Recent
          </button>

          <button onClick={() => setFilter("popular")}>
            Popular
          </button>

          <h5>Category</h5>

          <button onClick={() => setCategory("all")}>All</button>
          <button onClick={() => setCategory("notes")}>Notes</button>
          <button onClick={() => setCategory("projects")}>Projects</button>
          <button onClick={() => setCategory("guidance")}>Guidance</button>
          <button onClick={() => setCategory("career")}>Career</button>
          <button onClick={() => setCategory("skills")}>Skills</button>

        </div>

        {/* ✅ PASS STATE TO CHILD */}
        <div className="main">
          {children} ✅
        </div>

      </div>
    </div>
  );
}

export default Layout;
